python:
def factorial(n):
    if n > 1: return n * factorial(n-1)
    return 1
print(factorial(5))

javascript:
function factorial(n) {
  if (n > 1) return n * factorial(n-1);
  return 1;
}
console.log(factorial(5));

python:
def fib(n):
    if n > 1: return fib(n-1) + fib(n-2)
    return n
print(fib(10))

